func getFilterData(data *models.PageData) string {
	catID := getCategoryFilterValue(data)
	tagID := getTagFilterValue(data)
	tags := getTagsJson(data)
	return fmt.Sprintf("{ selectedCategory: '%s', selectedTag: '%s', allTags: [%s] }", catID, tagID, tags)
}

func getResultsData(data *models.PageData) string {
	tags := getTagsJson(data)
	return fmt.Sprintf("{ selected: [], bulkCategory: '', allTags: [%s], get allIds() { return Array.from(document.querySelectorAll('input[name=\\'transaction_ids\\']')).map(i => i.value); }, get isAllSelected() { const ids = this.allIds; return ids.length > 0 && ids.every(id => this.selected.includes(id)); }, toggleAll() { if (this.isAllSelected) { this.selected = []; } else { this.selected = this.allIds; } } }", tags)
}

func getSearchValue(data *models.PageData) string {
	if d, ok := data.Data.(models.TransactionPageData); ok {
		return d.Filters.Search
	}
	return ""
}

func getSortValue(data *models.PageData) string {
	if d, ok := data.Data.(models.TransactionPageData); ok {
		return d.Filters.SortBy + "_" + d.Filters.SortDir
	}
	return "date_desc"
}

func getCategoryFilterValue(data *models.PageData) string {
	if d, ok := data.Data.(models.TransactionPageData); ok && d.Filters.CategoryID != nil {
		return fmt.Sprint(*d.Filters.CategoryID)
	}
	return ""
}

func getTagFilterValue(data *models.PageData) string {
	if d, ok := data.Data.(models.TransactionPageData); ok && len(d.Filters.Tags) > 0 {
		return fmt.Sprint(d.Filters.Tags[0])
	}
	return ""
}

func getTagsJson(data *models.PageData) string {
	if d, ok := data.Data.(models.TransactionPageData); ok {
		var tags []string
		for _, t := range d.AllTags {
			tags = append(tags, fmt.Sprintf("{id: '%d', name: '%s', category_id: '%d'}", t.ID, t.Name, t.CategoryID))
		}
		return strings.Join(tags, ",")
	}
	return ""
}

func getMinAmount(data *models.PageData) string {
	if d, ok := data.Data.(models.TransactionPageData); ok && d.Filters.MinAmount != nil {
		return fmt.Sprintf("%.2f", *d.Filters.MinAmount)
	}
	return ""
}

func getMaxAmount(data *models.PageData) string {
	if d, ok := data.Data.(models.TransactionPageData); ok && d.Filters.MaxAmount != nil {
		return fmt.Sprintf("%.2f", *d.Filters.MaxAmount)
	}
	return ""
}

